#include "jayess_runtime.h"
#include <gtk/gtk.h>
#include <stdlib.h>
#include <string.h>

typedef struct jayess_gtk_widget_state {
    GtkWidget *widget;
    int destroy_on_close;
    int alive;
    struct jayess_gtk_signal_handler *first_handler;
    struct jayess_gtk_widget_state *first_child;
    struct jayess_gtk_widget_state *next_sibling;
} jayess_gtk_widget_state;

typedef struct jayess_gtk_signal_handler {
    char *signal;
    jayess_value *callback;
    struct jayess_gtk_signal_handler *next;
} jayess_gtk_signal_handler;

static char *jayess_gtk_dup(const char *text) {
    size_t length = 0;
    char *copy = NULL;
    if (text == NULL) {
        return NULL;
    }
    length = strlen(text);
    copy = (char *)malloc(length + 1);
    if (copy != NULL) {
        memcpy(copy, text, length + 1);
    }
    return copy;
}

static void jayess_gtk_free_handlers(jayess_gtk_signal_handler *handler) {
    while (handler != NULL) {
        jayess_gtk_signal_handler *next = handler->next;
        free(handler->signal);
        free(handler);
        handler = next;
    }
}

static void jayess_gtk_invoke_signal(jayess_gtk_signal_handler *handler) {
    if (handler == NULL || handler->callback == NULL) {
        return;
    }
    jayess_call_function(handler->callback, jayess_value_from_string(handler->signal != NULL ? handler->signal : ""));
}

static void jayess_gtk_clicked_cb(GtkWidget *widget, gpointer data) {
    (void)widget;
    jayess_gtk_invoke_signal((jayess_gtk_signal_handler *)data);
}

static void jayess_gtk_changed_cb(GtkWidget *widget, gpointer data) {
    (void)widget;
    jayess_gtk_invoke_signal((jayess_gtk_signal_handler *)data);
}

static void jayess_gtk_destroy_cb(GtkWidget *widget, gpointer data) {
    (void)widget;
    jayess_gtk_invoke_signal((jayess_gtk_signal_handler *)data);
}

static gboolean jayess_gtk_draw_cb(GtkWidget *widget, cairo_t *cr, gpointer data) {
    (void)widget;
    (void)cr;
    jayess_gtk_invoke_signal((jayess_gtk_signal_handler *)data);
    return FALSE;
}

static void jayess_gtk_mark_closed(jayess_gtk_widget_state *state) {
    jayess_gtk_widget_state *child = NULL;
    if (state == NULL || !state->alive) {
        return;
    }
    state->alive = 0;
    child = state->first_child;
    while (child != NULL) {
        jayess_gtk_mark_closed(child);
        child = child->next_sibling;
    }
}

static void jayess_gtk_widget_finalize(void *handle) {
    jayess_gtk_widget_state *state = (jayess_gtk_widget_state *)handle;
    if (state == NULL) {
        return;
    }
    if (state->alive) {
        GtkWidget *widget = state->widget;
        int destroy_on_close = state->destroy_on_close;
        jayess_gtk_mark_closed(state);
        if (destroy_on_close && widget != NULL) {
            gtk_widget_destroy(widget);
        }
    }
    jayess_gtk_free_handlers(state->first_handler);
    free(state);
}

static jayess_gtk_widget_state *jayess_gtk_expect_state(jayess_value *widget_value, const char *context) {
    jayess_gtk_widget_state *state = (jayess_gtk_widget_state *)jayess_expect_native_handle(widget_value, "GtkWidget", context);
    if (jayess_has_exception()) {
        return NULL;
    }
    if (state == NULL || !state->alive || state->widget == NULL) {
        jayess_throw_type_error(context);
        return NULL;
    }
    return state;
}

static jayess_value *jayess_gtk_wrap_widget(GtkWidget *widget) {
    jayess_gtk_widget_state *state = NULL;
    if (widget == NULL) {
        return jayess_value_undefined();
    }
    state = (jayess_gtk_widget_state *)calloc(1, sizeof(jayess_gtk_widget_state));
    if (state == NULL) {
        jayess_throw_error("failed to allocate GTK widget state");
        return jayess_value_undefined();
    }
    state->widget = widget;
    state->destroy_on_close = 1;
    state->alive = 1;
    return jayess_value_from_managed_native_handle("GtkWidget", state, jayess_gtk_widget_finalize);
}

jayess_value *jayess_gtk_init(void) {
    return jayess_value_from_bool(gtk_init_check(0, NULL));
}

jayess_value *jayess_gtk_create_window(void) {
    return jayess_gtk_wrap_widget(gtk_window_new(GTK_WINDOW_TOPLEVEL));
}

jayess_value *jayess_gtk_create_label(jayess_value *text_value) {
    const char *text = jayess_expect_string(text_value, "jayess_gtk_create_label");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    return jayess_gtk_wrap_widget(gtk_label_new(text));
}

jayess_value *jayess_gtk_create_button(jayess_value *text_value) {
    const char *text = jayess_expect_string(text_value, "jayess_gtk_create_button");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    return jayess_gtk_wrap_widget(gtk_button_new_with_label(text));
}

jayess_value *jayess_gtk_create_text_input(void) {
    return jayess_gtk_wrap_widget(gtk_entry_new());
}

jayess_value *jayess_gtk_create_image(jayess_value *path_value) {
    const char *path = jayess_expect_string(path_value, "jayess_gtk_create_image");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    return jayess_gtk_wrap_widget(gtk_image_new_from_file(path));
}

jayess_value *jayess_gtk_create_drawing_area(void) {
    return jayess_gtk_wrap_widget(gtk_drawing_area_new());
}

jayess_value *jayess_gtk_create_box(jayess_value *vertical_value, jayess_value *spacing_value) {
    GtkOrientation orientation = jayess_value_is_truthy(vertical_value) ? GTK_ORIENTATION_VERTICAL : GTK_ORIENTATION_HORIZONTAL;
    int spacing = (int)jayess_value_to_number(spacing_value);
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    return jayess_gtk_wrap_widget(gtk_box_new(orientation, spacing));
}

jayess_value *jayess_gtk_set_title(jayess_value *window_value, jayess_value *title_value) {
    jayess_gtk_widget_state *state = jayess_gtk_expect_state(window_value, "jayess_gtk_set_title");
    const char *title = jayess_expect_string(title_value, "jayess_gtk_set_title");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    gtk_window_set_title(GTK_WINDOW(state->widget), title);
    return jayess_value_undefined();
}

jayess_value *jayess_gtk_set_text(jayess_value *widget_value, jayess_value *text_value) {
    jayess_gtk_widget_state *state = jayess_gtk_expect_state(widget_value, "jayess_gtk_set_text");
    const char *text = jayess_expect_string(text_value, "jayess_gtk_set_text");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (GTK_IS_LABEL(state->widget)) {
        gtk_label_set_text(GTK_LABEL(state->widget), text);
        return jayess_value_undefined();
    }
    if (GTK_IS_BUTTON(state->widget)) {
        gtk_button_set_label(GTK_BUTTON(state->widget), text);
        return jayess_value_undefined();
    }
    if (GTK_IS_ENTRY(state->widget)) {
        gtk_entry_set_text(GTK_ENTRY(state->widget), text);
        return jayess_value_undefined();
    }
    jayess_throw_named_error("GTKError", "widget does not support text property updates");
    return jayess_value_undefined();
}

jayess_value *jayess_gtk_add_child(jayess_value *parent_value, jayess_value *child_value) {
    jayess_gtk_widget_state *parent = jayess_gtk_expect_state(parent_value, "jayess_gtk_add_child");
    jayess_gtk_widget_state *child = jayess_gtk_expect_state(child_value, "jayess_gtk_add_child");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    gtk_container_add(GTK_CONTAINER(parent->widget), child->widget);
    child->destroy_on_close = 0;
    child->next_sibling = parent->first_child;
    parent->first_child = child;
    return jayess_value_undefined();
}

jayess_value *jayess_gtk_connect_signal(jayess_value *widget_value, jayess_value *signal_value, jayess_value *callback_value) {
    jayess_gtk_widget_state *state = jayess_gtk_expect_state(widget_value, "jayess_gtk_connect_signal");
    const char *signal = jayess_expect_string(signal_value, "jayess_gtk_connect_signal");
    jayess_gtk_signal_handler *handler = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (callback_value == NULL || jayess_value_function_ptr(callback_value) == NULL) {
        jayess_throw_not_function();
        return jayess_value_undefined();
    }
    if (jayess_string_eq(signal, "clicked")) {
        handler = (jayess_gtk_signal_handler *)calloc(1, sizeof(jayess_gtk_signal_handler));
        if (handler == NULL) {
            jayess_throw_named_error("GTKError", "failed to allocate GTK signal handler");
            return jayess_value_undefined();
        }
        handler->signal = jayess_gtk_dup(signal);
        handler->callback = callback_value;
        handler->next = state->first_handler;
        state->first_handler = handler;
        g_signal_connect_data(state->widget, "clicked", G_CALLBACK(jayess_gtk_clicked_cb), handler, NULL, 0);
        return jayess_value_undefined();
    }
    if (jayess_string_eq(signal, "changed")) {
        handler = (jayess_gtk_signal_handler *)calloc(1, sizeof(jayess_gtk_signal_handler));
        if (handler == NULL) {
            jayess_throw_named_error("GTKError", "failed to allocate GTK signal handler");
            return jayess_value_undefined();
        }
        handler->signal = jayess_gtk_dup(signal);
        handler->callback = callback_value;
        handler->next = state->first_handler;
        state->first_handler = handler;
        g_signal_connect_data(state->widget, "changed", G_CALLBACK(jayess_gtk_changed_cb), handler, NULL, 0);
        return jayess_value_undefined();
    }
    if (jayess_string_eq(signal, "destroy")) {
        handler = (jayess_gtk_signal_handler *)calloc(1, sizeof(jayess_gtk_signal_handler));
        if (handler == NULL) {
            jayess_throw_named_error("GTKError", "failed to allocate GTK signal handler");
            return jayess_value_undefined();
        }
        handler->signal = jayess_gtk_dup(signal);
        handler->callback = callback_value;
        handler->next = state->first_handler;
        state->first_handler = handler;
        g_signal_connect_data(state->widget, "destroy", G_CALLBACK(jayess_gtk_destroy_cb), handler, NULL, 0);
        return jayess_value_undefined();
    }
    if (jayess_string_eq(signal, "draw")) {
        handler = (jayess_gtk_signal_handler *)calloc(1, sizeof(jayess_gtk_signal_handler));
        if (handler == NULL) {
            jayess_throw_named_error("GTKError", "failed to allocate GTK signal handler");
            return jayess_value_undefined();
        }
        handler->signal = jayess_gtk_dup(signal);
        handler->callback = callback_value;
        handler->next = state->first_handler;
        state->first_handler = handler;
        g_signal_connect_data(state->widget, "draw", G_CALLBACK(jayess_gtk_draw_cb), handler, NULL, 0);
        return jayess_value_undefined();
    }
    jayess_throw_named_error("GTKError", "unsupported GTK signal");
    return jayess_value_undefined();
}

jayess_value *jayess_gtk_emit_signal(jayess_value *widget_value, jayess_value *signal_value) {
    jayess_gtk_widget_state *state = jayess_gtk_expect_state(widget_value, "jayess_gtk_emit_signal");
    const char *signal = jayess_expect_string(signal_value, "jayess_gtk_emit_signal");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (!jayess_string_eq(signal, "clicked") && !jayess_string_eq(signal, "changed") && !jayess_string_eq(signal, "destroy") && !jayess_string_eq(signal, "draw")) {
        jayess_throw_named_error("GTKError", "unsupported GTK signal");
        return jayess_value_undefined();
    }
    g_signal_emit_by_name(state->widget, signal);
    return jayess_value_undefined();
}

jayess_value *jayess_gtk_queue_draw(jayess_value *widget_value) {
    jayess_gtk_widget_state *state = jayess_gtk_expect_state(widget_value, "jayess_gtk_queue_draw");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    gtk_widget_queue_draw(state->widget);
    return jayess_value_undefined();
}

jayess_value *jayess_gtk_show(jayess_value *widget_value) {
    jayess_gtk_widget_state *state = jayess_gtk_expect_state(widget_value, "jayess_gtk_show");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    gtk_widget_show_all(state->widget);
    return jayess_value_undefined();
}

jayess_value *jayess_gtk_hide(jayess_value *widget_value) {
    jayess_gtk_widget_state *state = jayess_gtk_expect_state(widget_value, "jayess_gtk_hide");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    gtk_widget_hide(state->widget);
    return jayess_value_undefined();
}

jayess_value *jayess_gtk_poll_events(void) {
    while (gtk_events_pending()) {
        gtk_main_iteration_do(FALSE);
    }
    return jayess_value_undefined();
}

jayess_value *jayess_gtk_run_main_loop(void) {
    gtk_main();
    return jayess_value_undefined();
}

jayess_value *jayess_gtk_quit_main_loop(void) {
    gtk_main_quit();
    return jayess_value_undefined();
}

jayess_value *jayess_gtk_destroy_window(jayess_value *widget_value) {
    return jayess_value_from_bool(jayess_value_close_native_handle(widget_value));
}
